2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // ===== Edge case: empty quote =====
6	  it("quote with empty item list returns premium 5 G (only processing fee)", () => {
7	    const result = quote({ customer: { yearsInsured: 0, previousContracts: 0 }, items: [] });
8	    expect(result.premium).toBe(5);
9	  });
10	
11	  // ===== Base premiums per item type =====
12	  it.todo("quote for a single plain sword (newcomer, first insurance) returns premium 115 G (100 base + 10 first + 5 fee)");
13	  it.todo("quote for a single plain amulet (newcomer, first insurance) returns premium 71 G (60 base + 6 first + 5 fee)");
14	  it.todo("quote for a single plain staff (newcomer, first insurance) returns premium 93 G (80 base + 8 first + 5 fee)");
15	  it.todo("quote for a single plain potion (newcomer, first insurance) returns premium 49 G (40 base + 4 first + 5 fee)");
16	  it.todo("quote for a single component (newcomer, first insurance) returns premium 33 G (25 base + 2.5 first → 27.5 + 5 fee = 32.5 → round up to 33 G)");
17	
18	  // ===== Block-of-3 alike components (base premium examples) =====
19	  it.todo("quote base premium for 2 runes is 50 G (no block)");
20	  it.todo("quote base premium for 3 runes is 60 G (block applies)");
21	  it.todo("quote base premium for 4 runes is 100 G (no block — block requires exactly 3)");
22	  it.todo("quote base premium for 7 runes is 175 G (no block: 7×25)");
23	
24	  // ===== Alike components clarification =====
25	  it.todo("quote base premium for 2 runes + 1 moonstone is 75 G (no block: different types)");
26	  it.todo("quote base premium for 3 runes + 3 moonstones is 120 G (two separate blocks)");
27	
28	  // ===== Item-specific modifiers in isolation =====
29	  it.todo("cursed sword item modifier adds 50% surcharge to that item's base (100 G → 150 G item subtotal)");
30	  it.todo("high-enchantment sword (enchantment 5) adds 30% surcharge to that item's base");
31	  it.todo("sword with enchantment 4 does NOT get high-enchantment surcharge");
32	  it.todo("cursed AND high-enchantment sword (enchantment 5) gets both surcharges");
33	
34	  // ===== Policy-wide modifiers in isolation =====
35	  it.todo("loyalty discount applies for customer with exactly 2 years (20% off policy base)");
36	  it.todo("loyalty discount does NOT apply for customer with 1 year");
37	  it.todo("first insurance surcharge adds 10% per item (each item in the quote is treated as first insurance)");
38	  it.todo("follow-up contract discount (-15%) applies to second quote in scenario");
39	
40	  // ===== Modifier scope (multi-item policy) =====
41	  it.todo("policy with cursed sword (100 G) + plain amulet (60 G) has policy base 160 G; curse adds 50 G (50% of sword only) → 210 G before policy modifiers and fee");
42	
43	  // ===== Integration: Newcomer with a cursed sword =====
44	  it.todo("newcomer (0 years) with cursed sword (steel, enchantment 3) gets premium 165 G (100 base + 50 curse + 10 first = 160 + 5 fee)");
45	
46	  // ===== Integration: Long-standing customer's second contract =====
47	  it.todo("3-year customer's second quote of cursed sword (steel, enchantment 7) gets premium 160 G (100 + 50 curse + 30 high-ench − 20 loyalty + 10 first − 15 follow-up = 155 + 5 fee)");
48	
49	  // ===== Rounding rules =====
50	  it.todo("premium calculation yielding 197.5 G is rounded UP to 198 G (in MHPCO's favor)");
51	  it.todo("intermediate amounts are kept as fractions; only the final premium is rounded");
52	
53	  // ===== Claim: standard reimbursement =====
54	  it.todo("claim on regular sword (steel, enchantment 3), damage 500 G → payout 400 G (500 − 100 deductible)");
55	  it.todo("claim on a rune (insurance value 250 G), damage 200 G → payout 100 G (200 − 100 deductible; no special clause for components)");
56	
57	  // ===== Claim: enchantment threshold and dragon material =====
58	  it.todo("claim on dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins: 500 − 100)");
59	  it.todo("claim on dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full reimbursement: 800 − 100)");
60	  it.todo("claim on steel sword, enchantment 9, damage 1000 G → payout 400 G (50% rule: 500 − 100)");
61	  it.todo("claim on dragon-material sword, enchantment exactly 8, damage 1000 G → payout 400 G (high-ench applies: 500 − 100)");
62	
63	  // ===== Claim: deductible per damage event =====
64	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → total payout 600 G (100 G deductible per damaged item: 400 + 200)");
65	
66	  // ===== Claim: multiple items of same type =====
67	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
68	  it.todo("dragon attack damages both of two insured swords → each damage entry gets its own deductible");
69	  it.todo("claim references more swords damaged than insured (2 sword damages, 1 sword insured) → error / rejection");
70	
71	  // ===== Claim: cap and insurance sum =====
72	  it.todo("policy with sword + amulet has insurance sum 1600 G and cap 3200 G");
73	  it.todo("policy with cursed sword has cap 2000 G (based on unmodified insurance value; premium modifiers don't raise cap)");
74	  it.todo("policy with sword + 3 runes (block) has insurance sum 1750 G (block discount affects premium only, not insurance sum)");
75	
76	  // ===== Claim: cap exhaustion across successive claims =====
77	  it.todo("sword insured (cap 2000 G), first claim of 1500 G → payout 1400 G, remainingCap 600 G");
78	  it.todo("after first claim used 1400 G, second claim of 1500 G → payout 600 G (reduced to remaining cap), remainingCap 0 G");
79	
80	  // ===== Claim: payout rounding =====
81	  it.todo("payout calculation yielding 350.5 G is rounded DOWN to 350 G (in MHPCO's favor)");
82	
83	  // ===== Edge cases / errors =====
84	  it.todo("quote with unknown item type (e.g. broomstick) → error");
85	  it.todo("claim references damage to item not in policy (e.g. amulet damaged when only sword insured) → error");
86	  it.todo("claim references damage to unknown item type → error");
87	  it.todo("claim with negative damage amount → error");
88	
89	  // ===== CLI =====
90	  it.todo("CLI reads JSON scenario from stdin and writes JSON results to stdout (schema-example scenario)");
91	  it.todo("CLI exits with non-zero status on unknown item type in quote; writes error to stderr; no results on stdout");
92	  it.todo("CLI exits with non-zero status when claim references item not in policy; writes error to stderr");
93	  it.todo("CLI exits with non-zero status when claim contains negative damage amount; writes error to stderr");
94	  it.todo("CLI exits with non-zero status when claim has more damages of a type than policy covers");
95	});
